diagnostics_hook:
#!/bin/bash
INPUT=$(head -c 65536); FILE=$(printf '%s' "$INPUT" | jq -r '.tool_input.file_path // ""')
[[ "$FILE" != *.ex && "$FILE" != *.exs ]] && { echo '{"decision":"approve"}'; exit 0; }
ERRORS=$(mix compile --warnings-as-errors --no-deps-check 2>&1 | tail -10)
echo "$ERRORS" | grep -qE 'error|warning' && echo "$ERRORS" >&2
echo '{"decision":"approve"}'
